pragma solidity ^0.8.20;

contract TokenVoting {
    address private owner;
    struct Candidate {
        string name;
        uint256 votes;
    }
    mapping(uint256 => Candidate) private candidates;
    mapping(address => bool) private voters;
    uint256 private candidateCount;

    event CandidateAdded(uint256 indexed id, string name);
    event VotingRightsGranted(address indexed voter);
    event VoteCast(address indexed voter, uint256 indexed candidateId);

    modifier onlyOwner() {
        require(msg.sender == owner, "Not the owner");
        _;
    }

    constructor() {
        owner = msg.sender;
    }

    function candidateCount() public view returns (uint256) {
        return candidateCount;
    }

    function candidateNames(uint256 id) public view returns (string memory) {
        require(id < candidateCount, "Invalid candidate ID");
        return candidates[id].name;
    }

    function candidateVotes(uint256 id) public view returns (uint256) {
        require(id < candidateCount, "Invalid candidate ID");
        return candidates[id].votes;
    }

    function addCandidate(string memory name) public onlyOwner {
        candidates[candidateCount] = Candidate(name, 0);
        candidateCount++;
        emit CandidateAdded(candidateCount - 1, name);
    }

    function grantVotingRights(address voter) public onlyOwner {
        require(!voters[voter], "Voting rights already granted");
        voters[voter] = true;
        emit VotingRightsGranted(voter);
    }

    function hasVotingRights(address voter) public view returns (bool) {
        return voters[voter];
    }

    function vote(uint256 candidateId) public {
        require(hasVotingRights(msg.sender), "No voting rights");
        require(candidateId < candidateCount, "Invalid candidate ID");
        require(candidates[candidateId].votes == 0, "Already voted");

        candidates[candidateId].votes++;
        voters[msg.sender] = false; // Remove voting rights after voting
        emit VoteCast(msg.sender, candidateId);
    }
}
